[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/dataset/longClinical/var/temperature> ;
            sh:resultMessage "A DDI-CDI InstanceVariable should use at least one cdi:uses Concept (or id-reference)" ;
            sh:resultPath cdi:uses ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI InstanceVariable should use at least one cdi:uses Concept (or id-reference)" ;
                    sh:minCount 1 ;
                    sh:path cdi:uses ;
                    sh:severity sh:Warning ] ] .

